// GraphQL Type Definitions
const typeDefs = gql`
  enum InvoiceStatus {
    DRAFT
    PENDING
    PAID
    OVERDUE
    CANCELLED
  }

  type InvoiceItem {
    description: String!
    quantity: Int!
    unitPrice: Float!
    amount: Float!
  }

  type Invoice {
    id: ID!
    invoiceNumber: String!
    clientName: String!
    clientEmail: String!
    items: [InvoiceItem!]!
    subtotal: Float!
    taxRate: Float!
    taxAmount: Float!
    totalAmount: Float!
    currency: String!
    status: InvoiceStatus!
    issuedDate: String!
    dueDate: String!
    paidDate: String
    notes: String
    createdBy: String!
    itemCount: Int!
  }

  type InvoiceSummary {
    totalInvoices: Int!
    totalAmount: Float!
    paidCount: Int!
    pendingCount: Int!
    overdueCount: Int!
    draftCount: Int!
  }

  type Query {
    invoice(id: ID!): Invoice
    invoices(status: InvoiceStatus, limit: Int, offset: Int): [Invoice!]!
    invoiceByNumber(invoiceNumber: String!): Invoice
    invoiceSummary: InvoiceSummary!
  }

  input InvoiceItemInput {
    description: String!
    quantity: Int!
    unitPrice: Float!
  }

  input CreateInvoiceInput {
    clientName: String!
    clientEmail: String!
    items: [InvoiceItemInput!]!
    taxRate: Float!
    currency: String
    dueDate: String!
    notes: String
  }

  input UpdateInvoiceStatusInput {
    id: ID!
    status: InvoiceStatus!
  }

  type Mutation {
    createInvoice(input: CreateInvoiceInput!): Invoice!
    updateInvoiceStatus(input: UpdateInvoiceStatusInput!): Invoice!
    deleteInvoice(id: ID!): Boolean!
  }
`;

// Resolver Implementation
const resolvers = {
  Invoice: {
    // Computed field: returns the count of line items on the invoice
    itemCount: (parent) => {
      return parent.items.length;
    }
  },

  Query: {
    // Fetch a single invoice by its ID
    invoice: (parent, { id }, context) => {
      const { user } = context;

      if (!user) {
        throw new Error('Authentication required.');
      }

      const invoice = invoices.find((inv) => inv.id === id);

      if (!invoice) {
        throw new Error(`Invoice with ID "${id}" not found.`);
      }

      return invoice;
    },

    // Fetch multiple invoices with optional filtering by status and pagination
    invoices: (parent, { status, limit, offset }, context) => {
      const { user } = context;

      if (!user) {
        throw new Error('Authentication required.');
      }

      let result = [...invoices];

      // Filter by status if provided
      if (status) {
        result = result.filter((inv) => inv.status === status);
      }

      // Apply pagination
      const startIndex = offset || 0;
      const endIndex = limit ? startIndex + limit : result.length;
      result = result.slice(startIndex, endIndex);

      return result;
    },

    // Fetch a single invoice by invoice number
    invoiceByNumber: (parent, { invoiceNumber }, context) => {
      const { user } = context;

      if (!user) {
        throw new Error('Authentication required.');
      }

      const invoice = invoices.find((inv) => inv.invoiceNumber === invoiceNumber);

      if (!invoice) {
        throw new Error(`Invoice with number "${invoiceNumber}" not found.`);
      }

      return invoice;
    },

    // Return an aggregated summary of all invoices
    invoiceSummary: (parent, args, context) => {
      const { user } = context;

      if (!user) {
        throw new Error('Authentication required.');
      }

      const totalInvoices = invoices.length;
      const totalAmount = invoices.reduce((sum, inv) => sum + inv.totalAmount, 0);
      const paidCount = invoices.filter((inv) => inv.status === 'PAID').length;
      const pendingCount = invoices.filter((inv) => inv.status === 'PENDING').length;
      const overdueCount = invoices.filter((inv) => inv.status === 'OVERDUE').length;
      const draftCount = invoices.filter((inv) => inv.status === 'DRAFT').length;

      return {
        totalInvoices,
        totalAmount: Math.round(totalAmount * 100) / 100,
        paidCount,
        pendingCount,
        overdueCount,
        draftCount
      };
    }
  },

  Mutation: {
    // Create a new invoice from input data
    createInvoice: (parent, { input }, context) => {
      const { user } = context;

      if (!user) {
        throw new Error('Authentication required.');
      }

      const { clientName, clientEmail, items, taxRate, currency, dueDate, notes } = input;

      // Build line items with calculated amounts
      const invoiceItems = items.map((item) => ({
        description: item.description,
        quantity: item.quantity,
        unitPrice: item.unitPrice,
        amount: Math.round(item.quantity * item.unitPrice * 100) / 100
      }));

      const subtotal = Math.round(invoiceItems.reduce((sum, item) => sum + item.amount, 0) * 100) / 100;
      const taxAmount = Math.round(subtotal * taxRate * 100) / 100;
      const totalAmount = Math.round((subtotal + taxAmount) * 100) / 100;

      const newId = String(invoices.length + 1);
      const invoiceNumber = `INV-2024-${String(invoices.length + 1).padStart(3, '0')}`;
      const issuedDate = new Date().toISOString().split('T')[0];

      const newInvoice = {
        id: newId,
        invoiceNumber,
        clientName,
        clientEmail,
        items: invoiceItems,
        subtotal,
        taxRate,
        taxAmount,
        totalAmount,
        currency: currency || 'USD',
        status: 'DRAFT',
        issuedDate,
        dueDate,
        paidDate: null,
        notes: notes || null,
        createdBy: user.id
      };

      invoices.push(newInvoice);

      return newInvoice;
    },

    // Update the status of an existing invoice
    updateInvoiceStatus: (parent, { input }, context) => {
      const { user } = context;

      if (!user) {
        throw new Error('Authentication required.');
      }

      const { id, status } = input;

      const invoiceIndex = invoices.findIndex((inv) => inv.id === id);

      if (invoiceIndex === -1) {
        throw new Error(`Invoice with ID "${id}" not found.`);
      }

      invoices[invoiceIndex].status = status;

      // Automatically set paidDate when status changes to PAID
      if (status === 'PAID') {
        invoices[invoiceIndex].paidDate = new Date().toISOString().split('T')[0];
      }

      return invoices[invoiceIndex];
    },

    // Delete an invoice by ID
    deleteInvoice: (parent, { id }, context) => {
      const { user } = context;

      if (!user) {
        throw new Error('Authentication required.');
      }

      const invoiceIndex = invoices.findIndex((inv) => inv.id === id);

      if (invoiceIndex === -1) {
        throw new Error(`Invoice with ID "${id}" not found.`);
      }

      invoices.splice(invoiceIndex, 1);

      return true;
    }
  }
};

// Simulated authentication middleware context
// In production, this would extract and verify tokens from request headers
function buildContext({ req }) {
  // Authentication middleware has already verified the user
  // Here we extract the authenticated user info from the request
  const user = {
    id: req.headers['x-user-id'] || 'user-101',
    email: req.headers['x-user-email'] || 'user@example.com',
    name: req.headers['x-user-name'] || 'Authenticated User'
  };

  return { user };
}

async function startServer() {
  const app = express();

  const server = new ApolloServer({
    typeDefs,
    resolvers,
    context: buildContext,
    formatError: (error) => {
      console.error('GraphQL Error:', error.message);
      return {
        message: error.message,
        path: error.path,
        extensions: {
          code: error.extensions?.code || 'INTERNAL_SERVER_ERROR'
        }
      };
    }
  });

  await server.start();
  server.applyMiddleware({ app, path: '/graphql' });

  const PORT = process.env.PORT || 4000;

  app.listen(PORT, () => {
    console.log(`Invoice Management GraphQL API running at http://localhost:${PORT}${server.graphqlPath}`);
    console.log(`\nExample queries:`);
    console.log(`  - Get invoice by ID: { invoice(id: "1") { id invoiceNumber clientName totalAmount status items { description amount } } }`);
    console.log(`  - Get all invoices: { invoices { id invoiceNumber clientName totalAmount status } }`);
    console.log(`  - Filter by status: { invoices(status: PAID) { id invoiceNumber totalAmount } }`);
    console.log(`  - Get summary: { invoiceSummary { totalInvoices totalAmount paidCount pendingCount } }`);
  });
}

startServer().catch((error) => {
  console.error('Failed to start server:', error);
  process.exit(1);
});

module.exports = { typeDefs, resolvers, invoices };